//! flux-image-server — sovereign IMAGE endpoint (non-token serving contract).
//!
//! Demonstrates the FLUX txt2img *serving contract* end-to-end on CPU: a prompt
//! (+ optional size/seed) comes in, PNG bytes go out. Unlike the text-token
//! `ServingPipeline`, this is an image contract (mirrors how the whisper host
//! returns a non-token result):
//!
//!   GET  /healthz            -> {"ok":true,"backend":"...","latent_max":N}
//!   GET  /generate?prompt=..&size=256&seed=7   -> 200 image/png  (PNG bytes)
//!   POST /generate           body = prompt text  (?size,?seed in query)  -> PNG
//!
//! The latent is seeded deterministically from (prompt, seed); the REAL FLUX
//! AutoencoderKL decoder (`model_flux_mmdit::FluxVae`) turns it into pixels.
//!
//! WEIGHTS: by default this loads a SYNTHETIC FLUX-VAE knot (`flux_vae_synth`)
//! so it runs with no multi-GB download — the decoder kernel is REAL but the
//! weights are not, so output is structured-but-NOT-prompt-faithful. Point
//! `--knot <path-or-url>` at the real `flux-1-schnell.knot` and wire the DiT
//! denoise (build_flux_real_image) ahead of decode for prompt fidelity.
//!
//!   cargo run --release --bin flux-image-server -- [--port 8099] [--knot PATH]

use std::sync::Arc;
use std::time::Instant;

use distributed_inference::flux_vae_synth::{gaussian, write_synthetic_flux_vae_knot};
use distributed_inference::loader::KnotWeights;
use distributed_inference::model_flux_mmdit::{FluxVae, FLUX_LATENT_CHANNELS};
use image::{codecs::png::PngEncoder, ColorType, ImageEncoder};
use tiny_http::{Header, Method, Response, Server};

const LATENT_MAX: usize = 64; // ≤ 512×512 output; guards CPU cost

fn arg(flag: &str, default: &str) -> String {
    let a: Vec<String> = std::env::args().collect();
    a.iter()
        .position(|x| x == flag)
        .and_then(|i| a.get(i + 1).cloned())
        .unwrap_or_else(|| default.to_string())
}

/// Parse `?k=v&...` from a request URL path.
fn query_param(url: &str, key: &str) -> Option<String> {
    let q = url.split_once('?')?.1;
    for pair in q.split('&') {
        if let Some((k, v)) = pair.split_once('=') {
            if k == key {
                return Some(urldecode(v));
            }
        }
    }
    None
}

fn urldecode(s: &str) -> String {
    let b = s.as_bytes();
    let mut out = Vec::with_capacity(b.len());
    let mut i = 0;
    while i < b.len() {
        match b[i] {
            b'%' if i + 2 < b.len() => {
                let h = |c: u8| (c as char).to_digit(16);
                if let (Some(hi), Some(lo)) = (h(b[i + 1]), h(b[i + 2])) {
                    out.push((hi * 16 + lo) as u8);
                    i += 3;
                    continue;
                }
                out.push(b[i]);
                i += 1;
            }
            b'+' => {
                out.push(b' ');
                i += 1;
            }
            c => {
                out.push(c);
                i += 1;
            }
        }
    }
    String::from_utf8_lossy(&out).into_owned()
}

fn prompt_seed(prompt: &str, seed: u64) -> u64 {
    let mut h = 0xCBF2_9CE4_8422_2325u64 ^ seed.rotate_left(17);
    for b in prompt.bytes() {
        h ^= b as u64;
        h = h.wrapping_mul(0x0000_0100_0000_01B3);
    }
    h | 1
}

/// prompt (+ seed) → seeded latents → REAL VAE decode → encoded PNG bytes.
fn render_png(vae: &FluxVae, prompt: &str, latent: usize, seed: u64) -> Result<Vec<u8>, String> {
    let (lh, lw) = (latent, latent);
    let mut st = prompt_seed(prompt, seed);
    let mut latents = vec![0.0f32; FLUX_LATENT_CHANNELS * lh * lw];
    for v in latents.iter_mut() {
        *v = gaussian(&mut st);
    }
    let rgb = vae.decode(&latents, lh, lw)?; // [h*w*3] interleaved, real kernel
    let (h, w) = (lh * 8, lw * 8);
    let mut png = Vec::new();
    PngEncoder::new(&mut png)
        .write_image(&rgb, w as u32, h as u32, ColorType::Rgb8)
        .map_err(|e| format!("png encode: {e}"))?;
    Ok(png)
}

fn json_response(code: u16, body: &str) -> Response<std::io::Cursor<Vec<u8>>> {
    Response::from_string(body.to_string())
        .with_status_code(code)
        .with_header(Header::from_bytes("Content-Type", "application/json").unwrap())
}

fn main() {
    let port: u16 = arg("--port", "8099").parse().unwrap_or(8099);
    let knot_arg = arg("--knot", "");
    let synthetic = knot_arg.is_empty();

    // Resolve a knot source. Default = a freshly-written synthetic VAE knot.
    let (knot_source, _tmp_guard): (String, Option<std::path::PathBuf>) = if synthetic {
        let p = std::env::temp_dir().join(format!("flux-image-server-{}.knot", std::process::id()));
        let t = Instant::now();
        let n = write_synthetic_flux_vae_knot(&p).expect("write synthetic knot");
        eprintln!(
            "[flux-image-server] SYNTHETIC VAE knot: {n} tensors → {} in {:?}",
            p.display(),
            t.elapsed()
        );
        (p.to_str().unwrap().to_string(), Some(p))
    } else {
        eprintln!("[flux-image-server] loading knot: {knot_arg}");
        (knot_arg.clone(), None)
    };

    let knot = KnotWeights::load(&knot_source).expect("load knot");
    let vae = Arc::new(FluxVae::load(&knot_source, &knot).expect("load FluxVae"));
    let backend = if synthetic { "vae-real/weights-synthetic" } else { "vae-real" };
    eprintln!(
        "[flux-image-server] FluxVae ready (backend={backend}); listening on http://127.0.0.1:{port}"
    );
    eprintln!("  GET  /healthz");
    eprintln!("  GET  /generate?prompt=a+red+fox&size=256&seed=7   -> image/png");

    let server = Server::http(("127.0.0.1", port)).expect("bind");
    for request in server.incoming_requests() {
        let url = request.url().to_string();
        let path = url.split('?').next().unwrap_or("/").to_string();
        let method = request.method().clone();

        if path == "/healthz" {
            let body = format!(
                "{{\"ok\":true,\"backend\":\"{backend}\",\"latent_max\":{LATENT_MAX},\"contract\":\"prompt->png\"}}"
            );
            let _ = request.respond(json_response(200, &body));
            continue;
        }

        if path != "/generate" {
            let _ = request.respond(json_response(404, "{\"error\":\"not found\"}"));
            continue;
        }

        // size (output px) and seed from query; prompt from query or POST body.
        let size: usize = query_param(&url, "size")
            .and_then(|s| s.parse().ok())
            .unwrap_or(256);
        let latent = (size / 8).clamp(1, LATENT_MAX);
        let seed: u64 = query_param(&url, "seed")
            .and_then(|s| s.parse().ok())
            .unwrap_or(42);

        let mut request = request;
        let prompt = match (&method, query_param(&url, "prompt")) {
            (_, Some(p)) => p,
            (Method::Post, None) => {
                let mut body = String::new();
                let _ = request.as_reader().read_to_string(&mut body);
                body.trim().to_string()
            }
            _ => String::new(),
        };
        if prompt.is_empty() {
            let _ = request.respond(json_response(400, "{\"error\":\"missing prompt\"}"));
            continue;
        }

        let t = Instant::now();
        match render_png(&vae, &prompt, latent, seed) {
            Ok(png) => {
                eprintln!(
                    "[flux-image-server] prompt={prompt:?} size={}x{} seed={seed} -> {} B in {:?}",
                    latent * 8,
                    latent * 8,
                    png.len(),
                    t.elapsed()
                );
                let resp = Response::from_data(png)
                    .with_status_code(200)
                    .with_header(Header::from_bytes("Content-Type", "image/png").unwrap())
                    .with_header(
                        Header::from_bytes("X-Image-Backend", backend.as_bytes()).unwrap(),
                    );
                let _ = request.respond(resp);
            }
            Err(e) => {
                let _ = request.respond(json_response(500, &format!("{{\"error\":\"{e}\"}}")));
            }
        }
    }
}
